// ── V2 Task Envelope: task_id propagation ─────────────────────────────────────
const _env = (typeof $input !== 'undefined' && $input.all()[0].json) || {};
const _envBody = _env.body || {};
const _inherited_task_id = _envBody.task_id || null;
const _gen_task_id = () => 'tid-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 9);
const _task_id = _inherited_task_id || _gen_task_id();
// ── End V2 Task Envelope ────────────────────────────────────────────────────────

const src = $input.all()[0];
// ── Loop prevention guard ────────────────────────────────────────────────────
const _incomingBody = (src.json && src.json.body) ? src.json.body : {};
const _attemptCount = (_incomingBody.attempt_count !== undefined)
    ? parseInt(_incomingBody.attempt_count, 10) || 0 : 0;
if (_attemptCount >= 1) {
    return [{ json: { loop_detected: true, original_task: _incomingBody,
        bot_name: 'ceo',
        task: 'loop_escalation', user_text: null, chat_id: null, from_agent: 'loop_guard',
        now_iso: new Date().toISOString(), daily_spec: [], weekly_spec: [] } }];
}
// ── End loop prevention ──────────────────────────────────────────────────────

// ── Deduplication guard ─────────────────────────────────────────────────────
const messageId = (src.json && src.json.message && src.json.message.message_id)
    ? String(src.json.message.message_id)
    : null;


// Detect trigger source by inspecting the item shape.
let task = 'scheduled_tick';
let user_text = null;
let chat_id = null;
let from_agent = 'system';

if (src.json && src.json.message && src.json.message.chat) {
    // Telegram trigger
    task = 'user_dm';
    let _utext = src.json.message.text || '';
    // Strip leading slash from Telegram commands so Super Agent does not classify them as shell commands.
    if (_utext.startsWith('/')) {
        const parts = _utext.slice(1).split(/\s+/);
        const cmd = (parts[0] || '').toLowerCase();
        const rest = parts.slice(1).join(' ');
        if (cmd === 'start' || cmd === 'help') { _utext = 'Hello - please introduce yourself, your role in Bridge Digital, and what you can help with right now.'; }
        else if (cmd === 'status') { _utext = 'Give me a brief status update on your current focus and any open items in your inbox.'; }
        else { _utext = (cmd + ' ' + rest).trim(); }
    }
    user_text = _utext;
    chat_id = src.json.message.chat.id;
    from_agent = 'user';
} else if (src.json && src.json.body && src.json.body.task) {
    // Webhook trigger
    task = src.json.body.task;
    user_text = src.json.body.message || null;
    from_agent = src.json.body.from_agent || 'system';
    chat_id = null; // webhooks do not carry a telegram chat
} else if (src.json && src.json.timestamp) {
    // Schedule trigger
    task = 'scheduled_tick';
    user_text = null;
    from_agent = 'system';
}

return [{ json: { message_id: messageId,
    bot_name: "ceo",
    task,
    user_text,
    chat_id,
    from_agent,
    now_iso: new Date().toISOString(),
    daily_spec: [{"hour": 16, "minute": 0, "task_name": "daily_exec_summary"}],
    weekly_spec: [{"weekday": 1, "hour": 9, "minute": 0, "task_name": "weekly_priority_alignment"}],
    task_id: _task_id,
} }];

const _buildTask = $('Build task payload').first().json;
if (_buildTask.loop_detected) {
    return [{ json: {
        message: JSON.stringify({ reply_text: '', actions: [{ type: 'no_op', payload: {
            reason: 'loop_detected', attempt_count: (_buildTask.original_task && _buildTask.original_task.attempt_count) || 1
        }}]}),
        session_id: 'bridge-loop-guard-' + Date.now(),
        task_kind: 'loop_escalation', user_chat_id: null,
        bot_name: _buildTask.bot_name || 'unknown', _pre_formed: true
    }}];
}

const task = $('Build task payload').first().json;
// ── Memory auto-block check (non-blocking) ──────────────────────────────────
let _autoBlockActive = false;
const _querySubject = task.user_text || task.subject || '';
if (_querySubject && _querySubject.length > 5) {
    try {
        const _memCheck = await $http.post(
            `${$env.SUPER_AGENT_URL || 'https://super-agent-production.up.railway.app'}/webhook/memory-query`,
            { project_name: _querySubject.slice(0, 100), api_key: $env.N8N_API_KEY || '' }
        );
        if (_memCheck && _memCheck.data && _memCheck.data.auto_block === true) {
            _autoBlockActive = true;
            return [{ json: {
                message: JSON.stringify({
                    reply_text: `🚫 AUTO-BLOCK: Project has been rejected ${_memCheck.data.rejection_count} time(s). Route to CRO then CEO for override.`,
                    actions: [{ type: 'no_op', payload: {
                        reason: 'auto_block_repeated_rejection',
                        rejection_count: _memCheck.data.rejection_count,
                        similar_projects: _memCheck.data.similar_projects
                    }}]
                }),
                session_id: `bridge-auto-block-${Date.now()}`,
                task_kind: 'auto_block', user_chat_id: task.chat_id,
                bot_name: task.bot_name, _pre_formed: true
            }}];
        }
    } catch(e) { /* non-blocking */ }
}


const inboxRow = $('Fetch open inbox').first().json || {};
const inbox = Array.isArray(inboxRow.open_inbox) ? inboxRow.open_inbox : [];
const teamPerf = inboxRow.team_performance_7d || {};
const activeDirectives = inboxRow.active_ceo_directives || {};
const staleHighCount = inboxRow.stale_high_priority_count || 0;
const totalOpenMemos = inboxRow.total_open_memos || 0;
const pendingProposals = Array.isArray(inboxRow.pending_proposals) ? inboxRow.pending_proposals : [];
const ctxRow = $('Fetch bot context').first().json || {};
const ctx = ctxRow.context ? [ctxRow.context] : [ctxRow];


const globalProtocol = `

GLOBAL OPERATING PROTOCOL (non-negotiable):
1. ALWAYS respond in valid JSON only. No prose, no markdown outside JSON strings.
2. EXACT response structure: {"reply_text": "...", "actions": [...]}
3. reply_text: human-readable Telegram message. Brief, role-appropriate.
4. actions: array of {type, payload} objects. Empty array if no actions.
5. NEVER include PLACEHOLDER, PASTE_, TBD, INSERT_HERE values in any field.
6. NEVER mention internal tools (n8n, shell, SQL, workflow IDs) in reply_text.
7. If required data is missing → return no_op with status "need_input" + list exact missing fields.
8. If blocked → escalate to Chief of Staff. NEVER retry autonomously.
9. MAX_RETRIES = 1. If attempt_count >= 1 in incoming body_json → return no_op immediately.
`;

const system = "You are Bridge_CEO_BOT, the strategic control system of Bridge Digital Solutions. You are not an idea generator. You are a profit-focused CEO who decides what the company pursues, drops, and doubles down on.

ROLE
Lead the AI enterprise with strategic clarity, discipline, and profit focus. Identify and propose new opportunities, prioritise projects, allocate budget with Finance, resolve agent disagreements, kill or pause underperforming projects, learn from outcomes, define strategic focus areas, and ensure only high-quality opportunities reach the human.

DECISION FRAMEWORK
For every opportunity (yours or proposed by Researcher/PM/BizDev), evaluate:
  - profit potential
  - time to revenue
  - execution complexity
  - resource cost (API tokens, infra hours, agent time)
  - strategic alignment with current focus area

Produce a PRIORITY SCORE 0-100 with the reason. Reject low-leverage work explicitly.

REQUIRED OUTPUT (when proposing or arbitrating)
- OPPORTUNITY NAME
- SUMMARY
- PRIORITY SCORE (0-100) + REASON
- STRATEGIC FIT (current focus / out-of-focus)
- HORIZON (short_term_cash | long_term_asset)
- RESOURCE DEMAND (estimated tokens, infra, agent hours)
- KEY RISKS
- GO / NO-GO RECOMMENDATION

LEARNING LOOP
After project outcomes (use bridge.workflow_events and billing_records to read recent results), record insight memos with:
  LESSONS LEARNED, WHAT WORKED, WHAT FAILED, STRATEGIC ADJUSTMENT.
Feed these back into future scoring decisions.

KILL SWITCH AUTHORITY
You may pause projects, cancel them mid-way, reallocate resources, and override non-critical agent disagreements. Triggers: budget overrun, low response rate, poor ROI signals, security blocks repeating, strategic drift. Issue a kill_switch directive memo to PM and Chief of Staff with the project_id and reason.

CAPITAL ALLOCATION
When Finance reports budget options, decide where it goes. Prefer fast cash flow over slow assets unless strategic horizon is explicitly long-term. State the choice and the rejected alternatives.

TRADE-OFF DECISION MAKER
When Finance, Marketing, BizDev, Security disagree, you are the final internal arbiter before human approval. Read the latest open memos from each conflicting party in the inbox before deciding.

STRATEGIC FOCUS
Maintain a single explicit focus area at any time (e.g. local services, AI SaaS, high-ticket B2B). Track it in a memo with subject Current strategic focus so other agents can read it. Reject opportunities outside this focus unless ROI score >= 80.

PERFORMANCE DASHBOARD
From bot_context (kpi_last_24h and kpi_last_7d), monitor: leads_created, demos_built, outreach_sent, interested_replies, invoices_paid, expenses_usd. React when any metric trends down for 3 consecutive periods.

OPPORTUNITY EVOLUTION
Before proposing a new idea, ask whether an existing project can be iterated to capture the same value. Prefer optimising live funnels over launching cold starts.

PRESSURE TEST MODE
Before endorsing any project for human approval, answer: what could go wrong? what would kill this? what assumption is weakest? Document the answers in body_json.pressure_test before issuing the approval_request.

REVENUE VALIDATION POLICY
When reviewing a project for human approval, you MUST include the latest revenue_review memo from bizdev. The Medium-risk approval DM template injects this automatically. If a project has no resolved revenue_review from bizdev, route a revenue_review_request to bizdev instead of approving; do not send an approval DM without revenue validation.

INTERACTION RULES
Work with Bridge_Chief_Of_Staff_bot as your main coordination proxy. Receive opportunities from Bridge_Researcher_bot and Bridge_Business_Development_bot. Coordinate with Finance / Bridge_Finance_KPI_Monitor for cost and revenue numbers. Use Bridge_Chief_Sec_Off_bot for enterprise risk posture. Use Bridge_PM_BOT for execution capacity.

ESCALATE OR INTERVENE WHEN priorities conflict materially, profit or budget performance deteriorates, a new idea shows major upside, strategic assumptions appear wrong, risk rises to leadership level, departments are misaligned, or the same project has been blocked by Security twice.

OUTPUT STYLE
Think and communicate like an owner: strategic, concise, decisive, high-signal. Reject more than you approve. Avoid spreading resources. Focus on highest-leverage actions.

SUCCESS DEFINITION
The company allocates effort toward the highest-value opportunities, kills weak projects early, learns from each outcome, and ships fewer but more profitable initiatives over time.


CRO GATE (MANDATORY — enforced on all project approvals):
When receiving any project proposal or approval_request:
  1. Check body_json.cro_score — MUST be present and >= 70
  2. Check body_json.recommendation — MUST be 'APPROVE'
  3. If cro_score missing or < 70 → route memo_type='cro_review_request' to CRO, do NOT approve
  4. If cro_score >= 70 → proceed with normal approval flow

FINAL PRIORITY SCORE = Base_PM_Score * 0.40 + cro_score * 0.40 + historical_confidence * 0.20

PERFORMANCE AWARENESS:
  Daily check /webhook/performance-dashboard for agent success rates.
  If any agent success_rate < 60% for 3 consecutive days → include in strategic memo to COS.
  If authority_level < 3 for any agent → require COS co-approval for that agent's decisions.

CTO AWARENESS:
The CTO bot owns all technical decisions and architecture. Nothing gets built without CTO approval.

WHEN RECEIVING PROJECT PROPOSALS:
1. Verify cto_review_complete exists in body_json (alongside cro_score)
2. If missing → ask COS to trigger CTO review before you approve
3. CTO recommendation = REJECT overrides your approval authority on technical grounds

FINAL APPROVAL SCORING:
  CRO score (40%) + CTO feasibility (20%) + Finance (20%) + Security (20%) = approval decision
  Minimum combined threshold: 70 points to approve

TECHNICAL VETO:
If CTO flags a fundamental technical risk (infrastructure failure, security hole, unresolvable dependency), you MUST respect the veto even if CRO score is high.
Document veto reason in bridge.project_memory for future reference.";

const contextBlock = JSON.stringify({
    now: task.now_iso,
    bot: task.bot_name,
    task_kind: task.task,
    open_inbox: inbox,
    total_open_memos: totalOpenMemos,
    stale_high_priority_count: staleHighCount,
    team_performance_7d: teamPerf,
    active_ceo_directives: activeDirectives,
    pending_improvement_proposals: pendingProposals,
    bot_context: ctx,
    daily_cadence: task.daily_spec,
    weekly_cadence: task.weekly_spec,
}, null, 2);

const taskBlock = task.task === 'user_dm'
    ? `The user sent you this message on Telegram:
${task.user_text}

Respond helpfully and consider issuing actions if appropriate.`
    : task.task === 'scheduled_tick'
      ? (task.task === 'weekly_priority_alignment' ? `WEEKLY TEAM INTELLIGENCE REVIEW: Analyse team_performance_7d for each bot. Identify the single most impactful improvement. If success_rate < 0.70 or a bot has had no runs in 48h, create a bot_improvement_proposal memo to chief_of_staff. Also process all open inbox items and archive resolved ones.` : `This is a scheduled cadence run. Process all open inbox items, escalate stale high-priority memos (stale_high_priority_count > 3), and archive anything resolved.`)
      : `An inter-agent invocation arrived from '${task.from_agent}': ${task.user_text || 'no message body'}. Decide how to respond.`;

const outputGuard = `

[OUTPUT FORMAT]
Return ONLY a JSON object (no prose, no markdown fences):
{
  "reply_text": "<what to send back via Telegram; empty string when a scheduled run should stay silent>",
  "actions": [
    {"type": "memo",     "payload": {"to_agent": "researcher|chief_of_staff|cso|ceo|cleaner|all", "memo_type": "status|proposal|directive|question|decision", "priority": "urgent|high|normal|low", "subject": "...", "body_json": {...}}},
    {"type": "archive",  "payload": {"memo_id": "<uuid-from-open-inbox>", "reason": "..."}},
    {"type": "query",    "payload": {"sql": "<safe single SELECT>"}},
    {"type": "escalate", "payload": {"subject": "...", "body_json": {...}}},
    {"type": "cleanup",  "payload": {"slug": "...", "reason": "..."}},
    {"type": "no_op",    "payload": {"reason": "..."}}
  ]
}
Keep actions <= 5. Never include non-whitelisted action types. User-facing commentary belongs in reply_text, not in alert actions.`;

const fullMessage = `${system}${globalProtocol}

[CONTEXT]
${contextBlock}

[TASK]
${taskBlock}${outputGuard}`;

return [{ json: {
    message: fullMessage,
    session_id: `bridge-${task.bot_name}-${task.now_iso.slice(0,16).replace(/[:T-]/g,'')}`,
    task_kind: task.task,
    user_chat_id: task.chat_id,
    bot_name: task.bot_name,
} }];

// ── Pre-formed short-circuit (loop guard) ──────────────────────────────────
const _upstream = $('Assemble prompt').first().json;
if (_upstream && _upstream._pre_formed) {
    let _pfActions;
    try { _pfActions = JSON.parse(_upstream.message).actions; } catch(e) { _pfActions = []; }
    return [{ json: {
        reply_text: '',
        actions: [{ type: 'no_op', risk: 'low',
            payload: (_pfActions[0] && _pfActions[0].payload) || { reason: 'loop_guard' } }],
        bot_name: _upstream.bot_name, user_chat_id: _upstream.user_chat_id,
        task_kind: 'loop_escalation', model_used: 'loop_guard', parse_error: null
    }}];
}

// ── Standard parse + risk + validation ─────────────────────────────────────
const raw = $json.response || '';
const riskMap = { "memo": "low", "archive": "low", "no_op": "low",
                  "escalate": "low", "query": "medium", "cleanup": "high" };
const defaultRisk = 'low';

let parsed = null, parseError = null;
try {
    let cleaned = raw.trim().replace(/^```(?:json)?/, '').replace(/```$/, '').trim();
    parsed = JSON.parse(cleaned);
} catch (e) { parseError = e.message; }
if (!parsed) {
    try { const m = raw.match(/\{[\s\S]*\}/); if (m) parsed = JSON.parse(m[0]); } catch (e) {}
}

let reply_text = '', actions = [];
if (parsed && typeof parsed === 'object' && parsed.reply_text !== undefined) {
    reply_text = typeof parsed.reply_text === 'string' ? parsed.reply_text : '';
    actions = Array.isArray(parsed.actions) ? parsed.actions.slice(0, 5) : [];
} else {
    reply_text = '';
    actions = [{ type: 'no_op', payload: {
        reason: 'json_parse_failed',
        parse_error: parseError || 'no structured response from model',
        raw_preview: String(raw).slice(0, 200)
    }}];
}

// ── Placeholder validation ──────────────────────────────────────────────────
const BANNED = ['PASTE_', 'TBD', 'PLACEHOLDER', 'INSERT_HERE', 'YOUR_URL'];
const hasPlaceholder = (str) => BANNED.some(p => String(str).includes(p));
if (hasPlaceholder(reply_text) || actions.some(a => hasPlaceholder(JSON.stringify(a)))) {
    reply_text = '[Output validation failed — response contained placeholder values. Please provide the actual value.]';
    actions = [{ type: 'no_op', payload: { reason: 'placeholder_detected' }}];
}

// ── Internal tool leakage scrubbing (non-blocking) ─────────────────────────
const leakageMap = {
    'n8n workflow creation': 'automation system modification',
    'n8n workflow modification': 'automation system modification',
    'shell command (destructive)': 'system operation',
    'shell command': 'system operation',
    'SQL query': 'data operation',
};
for (const [internal, safe] of Object.entries(leakageMap)) {
    if (reply_text.toLowerCase().includes(internal.toLowerCase()))
        reply_text = reply_text.replace(new RegExp(internal, 'gi'), safe);
}

// ── Risk annotation ─────────────────────────────────────────────────────────
const annotated = actions.map(a => {
    const type = (a && typeof a.type === 'string') ? a.type : 'no_op';
    let risk = riskMap[type] !== undefined ? riskMap[type] : defaultRisk;
    return { type, risk, payload: a.payload || {} };
});

const upstream = $('Assemble prompt').first().json;

// ── Telegram personality formatting ──────────────────────────────────────────
function _formatTgMsg(raw, taskKind) {
  if (!raw || raw.length < 3) return raw;

  // Parse ISO timestamp for the footer
  const _ts = new Date().toLocaleTimeString('en-GB', {hour:'2-digit',minute:'2-digit',timeZone:'UTC'}) + ' UTC';

  // Build structured header
  const _kind = (taskKind || 'report').replace(/_/g,' ');
  let header = '👑 *CEO — Gelson Mascarenhas*\n━━━━━━━━━━━━━━━━━━━━━━\n';

  // Transform the body: bold lines that look like labels, add section icons
  let body = raw
    .replace(/\*\*/g, '*')           // normalise bold markers
    .replace(/^(#+)\s+(.+)$/gm, (_, h, t) => '*' + t + '*')   // ## heading → bold
    .replace(/^[-•]\s+/gm, '  📌 ')                        // bullet → section icon
    .replace(/^(\w[^:\n]{2,40}):\s*(.+)$/gm, '*$1:* $2')    // Key: val → bold key
    .replace(/ERROR|FAILED|CRITICAL|BLOCKED/g, '🚨 $&')     // flag errors
    .replace(/SUCCESS|COMPLETE|DONE|APPROVED/gi, '✅ $&')     // flag successes
    .replace(/ACTION:|action:/g, '🎯 *ACTION:*')          // highlight actions
    ;

  // Escape Markdown special chars NOT inside existing bold spans
  // (Telegram Markdown v1: escape [ ] only)
  body = body.replace(/([\[\]])/g, '\\$1');

  const footer = '\n━━━━━━━━━━━━━━━━━━━━━━\n_⚡ Bridge Digital Solution_ · _' + _ts + '_';

  return header + body + footer;
}

// Apply formatting to reply_text if there is one
if ($json && $json.reply_text && $json.reply_text.length > 3) {
  const _taskKind = $json.task_kind || upstream && upstream.task_kind || '';
  $json.reply_text = _formatTgMsg($json.reply_text, _taskKind);
}

return [{ json: {
    reply_text, actions: annotated,
    bot_name: upstream.bot_name, user_chat_id: upstream.user_chat_id,
    task_kind: upstream.task_kind, model_used: $json.model_used || 'unknown',
    parse_error: parseError
}}];

const p = $json;
const out = [];
for (const a of (p.actions || [])) {
    out.push({ json: {
        action_type: a.type,
        action_risk: a.risk,
        action_payload: a.payload,
        bot_name: p.bot_name,
        user_chat_id: p.user_chat_id,
        task_kind: p.task_kind,
        model_used: p.model_used,
        reply_text: p.reply_text,
    }});
}
// Always emit at least one item so the reply path runs even when no actions.
if (out.length === 0) {
    out.push({ json: {
        action_type: 'no_op',
        action_risk: 'low',
        action_payload: { reason: 'no actions from LLM' },
        bot_name: p.bot_name,
        user_chat_id: p.user_chat_id,
        task_kind: p.task_kind,
        model_used: p.model_used,
        reply_text: p.reply_text,
    }});
}
return out;

